// API function pattern from bug-tracking.ts:
export async function getIssuePolicies(opts?: {filter?: string; offset?: number; limit?: number}) {
  const client = getClient();
  return client.getAllOffset<IssuePolicy>(
    '/api/policies/issue-policies',
    {_filter: opts?.filter, _offset: opts?.offset, _limit: opts?.limit},
    'application/vnd.polaris.policies.issue-policy-1+json',
    100
  );
}
